#include<stdio.h>
int main()
{
    int i,k,n,w;
    int sum=0;
    scanf("%d%d%d",&k,&n,&w);
    for(i=1;i<=w;i++)
    {
        sum+=i*k;
    }
    if(sum>n)
        {
            printf("%d\n",sum-n);

        }
    else
        printf("0\n");
    return 0;
}

