fn main() {
    let mut text = String::new();
    std::io::stdin().read_line(&mut text).expect("");
    let it : Vec<i32> = text.trim().split_whitespace().map(|x| x.parse::<i32>().expect("")).collect();
    let k = it[0];
    let n = it[1];
    let w = it[2];
    println!("{}", std::cmp::max((w + 1) * w / 2 * k - n, 0));
}
